<script setup>
import { computed,onMounted,ref } from 'vue'; import {useRoute,useRouter} from 'vue-router'; import {useVacanciesStore} from '../../stores/vacancies'; import AppInput from '../../components/AppInput.vue'; import AppTextarea from '../../components/AppTextarea.vue'; import AppSelect from '../../components/AppSelect.vue';
const route=useRoute(),router=useRouter(),store=useVacanciesStore(),edit=computed(()=>!!route.params.id),loading=ref(false),image=ref(null);const form=ref({codigo:'',titulo:'',departamentoEmpresaId:'',areaProfesionalId:'',ubicacionId:'',modalidadId:'',tipoContratoId:'',jornadaId:'',numeroPlazas:1,descripcion:'',funciones:'',requisitos:'',nivelAcademicoId:'',experienciaMinima:'',habilidadesDeseadas:'',salarioMinimo:'',salarioMaximo:'',mostrarSalario:false,fechaPublicacion:'',fechaCierre:'',imagenUrl:''});const options=(category)=>store.catalogs.filter(x=>x.categoria===category).map(x=>({value:x.id,label:x.nombre}));
onMounted(async()=>{await store.fetchCatalogs();if(edit.value){await store.fetchById(route.params.id,true);const v=store.current;if(v)Object.assign(form.value,{codigo:v.codigo,titulo:v.titulo,departamentoEmpresaId:v.departamento_empresa_id||'',areaProfesionalId:v.area_profesional_id||'',ubicacionId:v.ubicacion_id||'',modalidadId:v.modalidad_id||'',tipoContratoId:v.tipo_contrato_id||'',jornadaId:v.jornada_id||'',numeroPlazas:v.numero_plazas,descripcion:v.descripcion,funciones:v.funciones||'',requisitos:v.requisitos,nivelAcademicoId:v.nivel_academico_id||'',experienciaMinima:v.experiencia_minima||'',habilidadesDeseadas:v.habilidades_deseadas||'',salarioMinimo:v.salario_minimo||'',salarioMaximo:v.salario_maximo||'',mostrarSalario:v.mostrar_salario,fechaPublicacion:v.fecha_publicacion||'',fechaCierre:v.fecha_cierre||'',imagenUrl:v.imagen_url||''})}});
async function save(estado='borrador'){loading.value=true;let imagenUrl=form.value.imagenUrl;try{if(image.value)imagenUrl=await (await import('../../services/VacancyService')).default.uploadImage(image.value);const codigo=form.value.codigo.trim()||`VAC-${new Date().getFullYear()}-${crypto.randomUUID().slice(0,8).toUpperCase()}`;const payload={...form.value,codigo,imagenUrl,estado,id:route.params.id};const result=edit.value?await store.update(payload):await store.create(payload);if(result)router.push('/admin/vacantes')}finally{loading.value=false}}
</script>
<template><div><h2 class="mb-6 font-display text-xl font-bold">{{edit?'Editar vacante':'Nueva vacante'}}</h2><form @submit.prevent="save('borrador')" class="card space-y-5 border border-stone-100 p-6"><div class="grid gap-5 sm:grid-cols-2"><AppInput v-model="form.codigo" label="Código (opcional)" placeholder="Se genera automáticamente"/><AppInput v-model="form.titulo" label="Título" placeholder="Ej. Analista de datos"/></div><div class="grid gap-5 sm:grid-cols-3"><AppSelect v-model="form.departamentoEmpresaId" label="Departamento" :options="options('departamento')"/><AppSelect v-model="form.areaProfesionalId" label="Área profesional" :options="options('area_profesional')"/><AppSelect v-model="form.ubicacionId" label="Ubicación" :options="options('ubicacion')"/><AppSelect v-model="form.modalidadId" label="Modalidad" :options="options('modalidad')"/><AppSelect v-model="form.tipoContratoId" label="Contrato" :options="options('tipo_contrato')"/><AppSelect v-model="form.jornadaId" label="Jornada" :options="options('jornada')"/><AppSelect v-model="form.nivelAcademicoId" label="Nivel académico" :options="options('nivel_academico')"/><AppInput v-model="form.numeroPlazas" label="Número de plazas" type="number"/><AppInput v-model="form.experienciaMinima" label="Experiencia mínima" placeholder="Ej. 2 años"/></div><AppTextarea v-model="form.descripcion" label="Descripción" rows="5"/><AppTextarea v-model="form.funciones" label="Funciones" rows="4"/><AppTextarea v-model="form.requisitos" label="Requisitos" rows="4"/><AppTextarea v-model="form.habilidadesDeseadas" label="Habilidades deseadas" rows="3"/><div class="grid gap-5 sm:grid-cols-3"><AppInput v-model="form.salarioMinimo" label="Salario mínimo (USD)" type="number"/><AppInput v-model="form.salarioMaximo" label="Salario máximo (USD)" type="number"/><label class="flex items-center gap-2 pt-7 text-sm"><input v-model="form.mostrarSalario" type="checkbox"/> Mostrar salario</label><AppInput v-model="form.fechaPublicacion" label="Fecha de publicación" type="date"/><AppInput v-model="form.fechaCierre" label="Fecha límite" type="date"/><label class="text-sm font-medium">Imagen de vacante<input class="mt-2 block text-sm" type="file" accept="image/*" @change="e=>image=e.target.files[0]"/></label></div><p v-if="store.error" class="text-sm text-red-600">{{store.error}}</p><div class="flex gap-3"><button :disabled="loading" class="btn-secondary px-5 py-2.5 text-sm">Guardar borrador</button><button type="button" :disabled="loading" @click="save('publicada')" class="btn-primary px-5 py-2.5 text-sm">Publicar vacante</button></div></form></div></template>
